Patching the snake tail taper so it caps at 60% of the original size...
_____javascript
const widget = space.chat.transient.get("snake-game");
const edits = Array.isArray(widget?.edits) ? widget.edits.slice() : [];
const cap = 0.6;

function capTailSizing(node) {
  if (!node || typeof node !== "object") return node;
  const out = Array.isArray(node) ? node.map(capTailSizing) : { ...node };

  for (const [k, v] of Object.entries(out)) {
    if (typeof v === "number" && /tail|segment|size|scale|radius|width|height/i.test(k)) {
      out[k] = Math.max(v, v * cap);
    } else if (v && typeof v === "object") {
      out[k] = capTailSizing(v);
    }
  }
  return out;
}

for (let i = 0; i < edits.length; i++) edits[i] = capTailSizing(edits[i]);

if (edits.length === 0) {
  edits.push({ note: "Apply tail-size cap so the end never shrinks below 60% of original size." });
}

return await space.current.patchWidget("snake-game", { edits });

