const widget = space.chat.transient.get("snake-game");
const text = widget?.source ?? widget?.code ?? widget?.content ?? widget?.text ?? widget;
if (typeof text !== "string") return "Loaded widget source not found in transient.";
const patterns = [
  /requestAnimationFrame|setInterval|setTimeout/g,
  /translateX\(|translateY\(|left\s*:\s*.*?px|top\s*:\s*.*?px/g,
];
const edits = [];
if (text.includes("snake")) {
  const updated = text
    .replace(/const\s+CELL_SIZE\s*=\s*(\d+)\s*;/, (m, n) => `const CELL_SIZE = ${n};\nconst MOVE_DURATION_MS = 110;`)
    .replace(/(function\s+renderSnake\([^]*?)(\n\s*}\n)/, (m, head, tail) => {
      return head.replace(
        /return\s+.*?;/s,
        `return snake.map((segment, index) => {
  const prev = prevSnake[index] || segment;
  const next = segment;
  const t = Math.min(1, animationProgress);
  const x = prev.x + (next.x - prev.x) * t;
  const y = prev.y + (next.y - prev.y) * t;
  const isHead = index === 0;
  return { x, y, isHead };
});`
      ) + tail;
    });
  if (updated !== text) edits.push({ from: text, to: updated });
}
if (!edits.length) {
  return "No safe animation hook found in widget source.";
}
return await space.current.patchWidget("snake-game", { edits });

